def fibonacci():
    a, b = 0, 1
    while True:
        a, b = b, a + b
        yield a

def prime_fib(n: int):
    """ prime_fib returns n-th number that is a Fibonacci number and it's also prime. """
    if n < 1:
        raise ValueError("n must be a positive integer.")

    fib_gen = fibonacci()
    count = 0
    for fib in fib_gen:
        if is_prime(fib):
            count += 1
            if count == n:
                return fib
